#ifdef __cplusplus
extern "C" {
#endif

#include <omp.h>
#include <math.h>
#include <stdlib.h>

#define fp float

#define NUMBER_PAR_PER_BOX 100							
#define NUMBER_THREADS 128								

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))	

typedef struct
{
	fp x, y, z;
} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;
	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str
{
	fp alpha;
} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;
	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

void kernel_cpu(	par_str d_par_gpu,
					dim_str d_dim_gpu,
					box_str *d_box_gpu,
					FOUR_VECTOR *d_rv_gpu,
					fp *d_qv_gpu,
					FOUR_VECTOR *d_fv_gpu)
{
	int bx, wtx, j, k;
	fp a2;

	#pragma omp parallel private(bx, wtx, j, k, a2)
	{
		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
		FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
		fp qB_shared[NUMBER_PAR_PER_BOX];

		#pragma omp for schedule(static)
		for (bx = 0; bx < d_dim_gpu.number_boxes; bx++) {
			a2 = 2*d_par_gpu.alpha*d_par_gpu.alpha;

			int first_i = d_box_gpu[bx].offset;

			// Load rA_shared
			for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				rA_shared[wtx] = d_rv_gpu[first_i + wtx];
			}

			for (k = 0; k < (1 + d_box_gpu[bx].nn); k++) {
				int pointer;
				if (k == 0) {
					pointer = bx;
				} else {
					pointer = d_box_gpu[bx].nei[k - 1].number;
				}
				int first_j = d_box_gpu[pointer].offset;

				// Load rB_shared and qB_shared
				for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
					rB_shared[wtx] = d_rv_gpu[first_j + wtx];
					qB_shared[wtx] = d_qv_gpu[first_j + wtx];
				}

				// Compute forces
				#pragma omp for schedule(static) nowait
				for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
					fp fv_v = 0.0f;
					fp fv_x = 0.0f;
					fp fv_y = 0.0f;
					fp fv_z = 0.0f;
					for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
						fp r2 = rA_shared[wtx].v + rB_shared[j].v - DOT(rA_shared[wtx], rB_shared[j]); 
						fp u2 = a2 * r2;
						fp vij = expf(-u2);
						fp fs = 2 * vij;
						THREE_VECTOR d;
						d.x = rA_shared[wtx].x - rB_shared[j].x;
						d.y = rA_shared[wtx].y - rB_shared[j].y;
						d.z = rA_shared[wtx].z - rB_shared[j].z;
						fp fxij = fs * d.x;
						fp fyij = fs * d.y;
						fp fzij = fs * d.z;
						fv_v += qB_shared[j] * vij;
						fv_x += qB_shared[j] * fxij;
						fv_y += qB_shared[j] * fyij;
						fv_z += qB_shared[j] * fzij;
					}
					#pragma omp atomic
					d_fv_gpu[first_i + wtx].v += fv_v;
					#pragma omp atomic
					d_fv_gpu[first_i + wtx].x += fv_x;
					#pragma omp atomic
					d_fv_gpu[first_i + wtx].y += fv_y;
					#pragma omp atomic
					d_fv_gpu[first_i + wtx].z += fv_z;
				}
			}
		}
	}
}

void 
kernel_gpu_opencl_wrapper(	par_str par_cpu,
							dim_str dim_cpu,
							box_str* box_cpu,
							FOUR_VECTOR* rv_cpu,
							fp* qv_cpu,
							FOUR_VECTOR* fv_cpu)
{
	// Just call kernel_cpu in place of OpenCL kernel
	kernel_cpu(par_cpu, dim_cpu, box_cpu, rv_cpu, qv_cpu, fv_cpu);
}

#ifdef __cplusplus
}
#endif
